package ru.memearena.meme.infrastructure;
import jakarta.persistence.LockModeType; import org.springframework.data.domain.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import ru.memearena.meme.domain.*; import java.util.*;
public interface MemeRepository extends JpaRepository<Meme,UUID>{ boolean existsByMediaAssetId(UUID mediaAssetId); Optional<Meme> findByMediaAssetId(UUID mediaAssetId); Page<Meme> findByModerationStatus(ModerationStatus s, Pageable p); @Query("select m from Meme m where m.id in :ids order by m.id") @Lock(LockModeType.PESSIMISTIC_WRITE) List<Meme> lockByIdInOrder(@Param("ids") Collection<UUID> ids); @Query(value="select m1.* from meme m1 join meme m2 on m1.id<>m2.id where m1.moderation_status='APPROVED' and m2.moderation_status='APPROVED' and not exists (select 1 from vote v where v.user_id=:userId and v.pair_key = case when cast(m1.id as text) < cast(m2.id as text) then cast(m1.id as text)||':'||cast(m2.id as text) else cast(m2.id as text)||':'||cast(m1.id as text) end) order by random() limit 1", nativeQuery=true) Optional<Meme> findRandomLeft(@Param("userId") UUID userId); @Query(value="select m2.* from meme m1 join meme m2 on m1.id<>m2.id where m1.id=:leftId and m2.moderation_status='APPROVED' and not exists (select 1 from vote v where v.user_id=:userId and v.pair_key = case when cast(m1.id as text) < cast(m2.id as text) then cast(m1.id as text)||':'||cast(m2.id as text) else cast(m2.id as text)||':'||cast(m1.id as text) end) order by random() limit 1", nativeQuery=true) Optional<Meme> findRandomRight(@Param("userId") UUID userId,@Param("leftId") UUID leftId); @Query("select m from Meme m where m.moderationStatus=ru.memearena.meme.domain.ModerationStatus.APPROVED order by m.rating desc, m.battlesCount desc, m.createdAt asc") List<Meme> topAllTime(Pageable p); @Query("select m from Meme m where m.id in :ids") List<Meme> findAllByIds(@Param("ids") Collection<UUID> ids); @Query("select m from Meme m where m.approvalCohortDate=:d and m.moderationStatus=ru.memearena.meme.domain.ModerationStatus.APPROVED") List<Meme> findApprovedByCohort(@Param("d") java.time.LocalDate d); }
